def is_prime(number: int) -> bool:
    if number < 2:
        return False
    for divisor in range(2, int(number ** 0.5) + 1):
        if number % divisor == 0:
            return False
    return True

def normalise(values):
    total = sum(values)
    if total == 0:
        return [0 for _ in values]
    return [value / total for value in values]

